// proxy and reads t.co / an intermediate, missing the block. POLL instead: keep
// looking until we either see Akamai's "Access Denied" (throw, so the run
// rotates proxy) or the real LA28 page (continue). Navigations during the poll
// destroy this isolated world; the engine retries the whole node on the settled
// page, so the poll always ends up on the final document.
function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function denied(){
  var title=(document.title||'').trim();
  var body=(document.body?document.body.innerText:'')||'';
  return /access denied/i.test(title)
    || (/access denied/i.test(body) && /(don't have permission|reference #|edgesuite\.net)/i.test(body));
}
function la28Ready(){
  // Positive proof we reached the real LA28 site (not t.co / an intermediate) so
  // we can stop early on a clean run instead of polling the full window.
  var title=(document.title||'').trim();
  if(/official la28|la28.*(ticket|olympic|paralympic)/i.test(title)) return true;
  var host=(location.host||'');
  var body=(document.body?document.body.innerText:'')||'';
  return /la28\.org/i.test(host)
    && /register for the la28|get tickets|waiting room|create an account|legal terms and privacy|mark your calendar/i.test(body);
}
var start=Date.now();
