var deadline=Date.now()+20000;
while(Date.now()<deadline){
  if(denied()) throw new Error('LA28 Access Denied - this proxy IP is blocked. Use a different proxy.');
  if(la28Ready()) return (document.title||'').trim();
  await sleep(500);
}
if(denied()) throw new Error('LA28 Access Denied - this proxy IP is blocked. Use a different proxy.');
return (document.title||'').trim();

// Wait for the asynchronously-rendered privacy modal, but do not synthesize
// a DOM click here. The true branch uses the engine's native click node.
function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function visible(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>1&&r.height>1&&s.visibility!=='hidden'&&s.display!=='none'&&parseFloat(s.opacity||'1')>0.05;}
var deadline=Date.now()+10000;
while(Date.now()<deadline){var a=document.querySelector('#cmpwelcomebtnyes > a'),box=document.querySelector('#cmpwelcomebtnyes');if(a&&(visible(a)||visible(box)))return '1';await sleep(250);}
return '';

// Confirm the native click closed the modal before queue navigation.
function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function visible(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>1&&r.height>1&&s.visibility!=='hidden'&&s.display!=='none'&&parseFloat(s.opacity||'1')>0.05;}
var deadline=Date.now()+5000;while(Date.now()<deadline){if(!visible(document.querySelector('#cmpwelcomebtnyes > a'))&&!visible(document.querySelector('#cmpwelcomebtnyes')))return 'closed';await sleep(200);}
throw new Error('LA28 privacy popup remained open after native click (#cmpwelcomebtnyes > a).');

// LA28 legal modal's actual clickable control. Its visible CONTINUE label
// may live below the anchor, so target the stable clickable selector directly.
var b=document.querySelector('#cmpwelcomebtnyes > a');
if(!b)return 'absent';
var r=b.getBoundingClientRect(),s=getComputedStyle(b);
if(r.width<2||r.height<2||s.visibility==='hidden'||s.display==='none')return 'hidden';
try{b.scrollIntoView({block:'center'});}catch(e){}
try{b.focus();}catch(e){}
b.click();
