// Dismiss the LA28 Legal Terms and Privacy overlay wherever its CONTINUE
// label lives (button child, open shadow root, or same-origin iframe).
function visible(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>1&&r.height>1&&s.visibility!=='hidden'&&s.display!=='none'&&parseFloat(s.opacity||'1')>0.05;}
function roots(){var out=[document],stack=[document];while(stack.length){var root=stack.pop(),els=[];try{els=root.querySelectorAll('*');}catch(e){}for(var i=0;i<els.length;i++){if(els[i].shadowRoot){out.push(els[i].shadowRoot);stack.push(els[i].shadowRoot);}}}var frames=document.querySelectorAll('iframe');for(var j=0;j<frames.length;j++){try{if(frames[j].contentDocument)out.push(frames[j].contentDocument);}catch(e){}}return out;}
var rs=roots();for(var i=0;i<rs.length;i++){var body='';try{body=(rs[i].body?rs[i].body.innerText:(rs[i].host?rs[i].host.innerText:''))||'';}catch(e){}if(!/legal terms and privacy|terms & conditions.*privacy policy/i.test(body))continue;var nodes=[];try{nodes=rs[i].querySelectorAll('#cmpbntyestxt,button,a,[role=button],input[type=button],input[type=submit],span,div,p');}catch(e){}for(var j=0;j<nodes.length;j++){var el=nodes[j],txt=(el.innerText||el.textContent||el.value||'').replace(/\s+/g,' ').trim();if(!visible(el)||!/^continue$/i.test(txt))continue;var r=el.getBoundingClientRect();if(r.width>900||r.height>160)continue;var target=(el.closest&&el.closest('button,a,[role=button],input[type=button],input[type=submit],[onclick]'))||el;try{target.scrollIntoView({block:'center'});}catch(e){}try{target.focus();}catch(e){}target.click();return 'clicked';}}return 'absent';

