// Classify the current Queue-it/LA28 page. The graph loops on 'wait' so
// cancellation remains responsive between checks; blocked pages fail immediately.
function visible(el){
  if(!el)return false;
  var r=el.getBoundingClientRect();
  if(r.width<2||r.height<2)return false;
  var s=getComputedStyle(el);
  return s.visibility!=='hidden'&&s.display!=='none'&&parseFloat(s.opacity||'1')>0.05;
}
function blocked(){
  var title=(document.title||'').trim();
  var body=(document.body?document.body.innerText:'')||'';
  var href=(location.href||'').toLowerCase();
  return /error403|access[-_/]?denied|restricted[-_/]?access/.test(href)
    || /access denied|restricted access/i.test(title)
    || /your access has been restricted|access has been restricted|you do not have permission to access/i.test(body);
