function clickKeepAlive(){
  var body=(document.body?document.body.innerText:'')||'';
  if(!/don.?t lose your spot|confirm you.?re still here|lose your position in the queue/i.test(body))return false;
  var nodes=document.querySelectorAll('button, a, [role=button], input[type=button], input[type=submit]');
  for(var i=0;i<nodes.length;i++){
    var el=nodes[i];
    if(!visible(el))continue;
    var txt=(el.innerText||el.textContent||el.value||el.getAttribute&&el.getAttribute('aria-label')||'').replace(/\s+/g,' ').trim();
    if(!/^(confirm|i.?m still here|stay in queue)$/i.test(txt))continue;
    var target=(el.closest&&el.closest('button,a,[role=button],input'))||el;
    try{target.scrollIntoView({block:'center'});}catch(e){}
    try{target.click();}catch(e){}
    return true;
  }
  return false;
}
function clickProceed(){
  var el=null;
  try{
    el=document.evaluate('/html/body/div[2]/div[2]/div[3]/a/div',document,null,XPathResult.FIRST_ORDERED_NODE_TYPE,null).singleNodeValue;
