clickProceed();
try{var b=document.querySelector('button.cmpwelcomebtnyes');if(visible(b))b.click();}catch(e){}
return 'wait';

// Queue-it periodically asks the visitor to prove they are still present.
// Use its stable element id rather than relying on translated/changing button text.
var b=document.querySelector('#buttonConfirmVisitorPresence');
if(!b)return 'absent';
var r=b.getBoundingClientRect();
var s=getComputedStyle(b);
if(r.width<2||r.height<2||s.visibility==='hidden'||s.display==='none')return 'hidden';
try{b.scrollIntoView({block:'center'});}catch(e){}
try{b.focus();}catch(e){}
b.click();
return 'clicked';

const el = document.evaluate('/html/body/div[2]/div[2]/div[3]/a/div', document, null, XPathResult.FIRST_ORDERED_NODE_TYPE, null).singleNodeValue;
if (!el) return '';
const r = el.getBoundingClientRect();
return (r.width > 0 && r.height > 0) ? '1' : '';

// Dismiss LA28's first-load consent gate ("Legal Terms and Privacy" CONTINUE,
// and/or a cookie CMP). Searches the main DOM, OPEN shadow roots, and
// same-origin iframes for the consent button (by id or exact visible text),
// prefers one inside a modal/overlay, clicks it, and confirms it closed.
// If nothing reachable is found it throws a DIAG string listing iframes +
// shadow hosts so the exact structure (e.g. a cross-origin CMP iframe) is known.
function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function vis(el){
  if(!el)return false;
  var r=el.getBoundingClientRect();
  if(r.width<2||r.height<2)return false;
  var s=getComputedStyle(el);
  if(s.visibility==='hidden'||s.display==='none'||parseFloat(s.opacity||'1')<0.05)return false;
  var W=window.innerWidth||9999,H=window.innerHeight||9999;
  if(r.bottom<0||r.top>H||r.right<0||r.left>W)return false;
  return true;
}
function parentOf(n){
  var p=n.parentElement;
  if(!p){var rt=n.getRootNode&&n.getRootNode();p=(rt&&rt.host)||null;}
  return p;
}
function inOverlay(el){
  var n=el;
  while(n&&n.nodeType===1){
    if(n.getAttribute&&(n.getAttribute('role')==='dialog'||n.getAttribute('aria-modal')==='true'))return true;
    try{var s=getComputedStyle(n);if((s.position==='fixed'||s.position==='sticky')&&parseInt(s.zIndex||'0',10)>=5)return true;}catch(e){}
    if(n===document.body)break;
    n=parentOf(n);
  }
  return false;
}
function clickIt(el){
  var t=(el.closest&&el.closest('button, a, [role=button], input[type=submit], input[type=button], [onclick]'))||el;
  try{t.scrollIntoView({block:'center'});}catch(e){}
  try{t.click();}catch(e){}
  if(t!==el){try{el.click();}catch(e){}}
}
function allRoots(){
  var roots=[document],stack=[document];
  while(stack.length){
    var root=stack.pop(),els;
    try{els=root.querySelectorAll('*');}catch(e){continue;}
    for(var i=0;i<els.length;i++){var sh=els[i].shadowRoot;if(sh){roots.push(sh);stack.push(sh);}}
  }
  var ifr=document.querySelectorAll('iframe');
  for(var j=0;j<ifr.length;j++){var dd=null;try{dd=ifr[j].contentDocument;}catch(e){}if(dd)roots.push(dd);}
  return roots;
}
function findIn(root){
  try{var byId=root.querySelector('#cmpbntyestxt');if(byId&&vis(byId))return byId;}catch(e){}
  var exact=/^(continue|i agree|agree|accept all|accept cookies|accept|allow all|got it|ok)$/i;
  var nodes;
  try{nodes=root.querySelectorAll('button, a, [role=button], input[type=submit], input[type=button], span, div, p');}catch(e){return null;}
  var best=null;
  for(var i=0;i<nodes.length;i++){
    var el=nodes[i];
    if(!vis(el))continue;
    var txt=(el.innerText||el.textContent||el.value||'').replace(/\s+/g,' ').trim();
    if(!exact.test(txt))continue;
    var r=el.getBoundingClientRect();
    if(r.height>140||r.width>900)continue;
    if(inOverlay(el))return el;
    if(!best)best=el;
  }
  return best;
}
function pick(){var roots=allRoots();for(var i=0;i<roots.length;i++){var el=findIn(roots[i]);if(el)return el;}return null;}
function diag(){
  var out={rs:document.readyState,iframes:[],shadowHosts:[],btns:[]};
  var ifr=document.querySelectorAll('iframe');
  for(var i=0;i<ifr.length;i++){var co;try{co=ifr[i].contentDocument?'same':'cross';}catch(e){co='cross';}out.iframes.push(((ifr[i].src||'no-src').slice(0,90))+' ['+co+']');}
  var all=document.querySelectorAll('*');
  for(var j=0;j<all.length;j++){if(all[j].shadowRoot)out.shadowHosts.push(all[j].tagName.toLowerCase()+(all[j].id?('#'+all[j].id):''));}
  var cl=document.querySelectorAll('button, a, [role=button], input[type=submit], input[type=button]');
  for(var k=0;k<cl.length&&out.btns.length<20;k++){if(vis(cl[k])){var t=(cl[k].innerText||cl[k].value||'').replace(/\s+/g,' ').trim().slice(0,28);if(t)out.btns.push(t);}}
  return out;
}
var start=Date.now();
while(document.readyState!=='complete'&&Date.now()-start<15000){await sleep(200);}
