// Persist after Log In until LA28 exposes a real next state. Gigya can leave the
// page spinner up for much longer than its initial network request, so elapsed time alone
// must never be treated as an OTP transition or successful authentication.
function visible(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>1&&r.height>1&&s.visibility!=='hidden'&&s.display!=='none'&&parseFloat(s.opacity||'1')>0.05;}
function first(sels){for(var i=0;i<sels.length;i++){var nodes=[];try{nodes=document.querySelectorAll(sels[i]);}catch(e){}for(var j=0;j<nodes.length;j++){if(visible(nodes[j]))return nodes[j];}}return null;}
function errorText(el){return ((el&&el.textContent)||'').replace(/\s+/g,' ').trim();}
var tries=Number("{{capState.tries}}")||0;
var title=(document.title||'').trim();
var href=(location.href||'').toLowerCase();
if(/profile\s*[-\u2013|]\s*official\s+la28/i.test(title)||/(\/profile|\/mycustomerdata|\/myprofile)/.test(href)||first(['app-sports-profile-lotteries','button[data-qa="save-data-button"]']))return {state:'profile',tries:tries};
if(first(['input#gigya-textbox-code','form#gigya-otp-update-form input[name="code"]','form#gigya-otp-update-form input[type="text"]']))return {state:'otp',tries:tries};
var errors=[];try{errors=document.querySelectorAll('.gigya-error-msg-active,[class*="gigya-error-code-"]');}catch(e){}
var other='';
for(var i=0;i<errors.length;i++){
  if(!visible(errors[i]))continue;
  var cls=String(errors[i].className||''),txt=errorText(errors[i]);
  if(/gigya-error-code-401020|gigya-error-code-401023/.test(cls)||/not a robot|captcha|recaptcha/i.test(txt)){
    if(tries>=3)throw new Error('LA28 login captcha was rejected after 3 solve attempts.');
    return {state:'captcha',tries:tries+1};
  }
  if(txt&&!other)other=txt;
}
if(other)throw new Error('LA28 login failed: '+other.slice(0,240));
return {state:'wait',tries:tries};

// After clicking Log In, Gigya rejects with a captcha error until the reCAPTCHA
// is satisfied - code 401020 OR 401023 ("confirm you are not a robot"). Each
// failed submit can raise a FRESH captcha, so this node runs after EVERY
// (re-)login: return flag '1' to solve+retry (bounded to 3 attempts via
// capState.tries), or '' to stop and continue to the profile/email path.
function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function vis(el){
  if(!el) return false;
  var r=el.getBoundingClientRect();
  if(r.width<1||r.height<1) return false;
  var s=getComputedStyle(el);
  return s.display!=='none'&&s.visibility!=='hidden'&&parseFloat(s.opacity||'1')>0.05;
}
function capErr(){
  var all=document.querySelectorAll('.gigya-error-msg-active, [class*="gigya-error-code-"]');
  for(var i=0;i<all.length;i++){
    var el=all[i], cls=el.className||'';
    if(!(el.classList.contains('gigya-error-msg-active')||vis(el))) continue;
    if(/gigya-error-code-401020|gigya-error-code-401023/.test(cls)) return true;
    if(/not a robot|captcha|recaptcha/i.test(el.textContent||'')) return true;
  }
  return false;
}
var tries = Number("{{capState.tries}}") || 0;
var deadline=Date.now()+8000, hit=false;
while(Date.now()<deadline){ if(capErr()){hit=true;break;} await sleep(400); }
if(!hit) hit=capErr();
var go = hit && tries < 3;
return { flag: go ? '1' : '', tries: tries + (go ? 1 : 0) };

// After clicking Save, wait for the page to settle, then count the success
// checkmarks (<i class="icon icon-checkmark">). Success is EXACTLY 4. Wait for
// the count to stabilize (same across 2 reads) so the exact check compares the
// final value, not a mid-render count. Return the settled count for the branch.
function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function count(){ return document.querySelectorAll('i.icon-checkmark').length; }
await sleep(1500);                         // let the Save submit begin navigating/updating
var start=Date.now();
while(document.readyState!=='complete'&&Date.now()-start<30000){await sleep(200);}
var deadline=Date.now()+20000, prev=-1, stable=0, n=0;
while(Date.now()<deadline){
  n=count();
  if(n===prev){ if(n>0 && ++stable>=2) break; } else { stable=0; }
  prev=n;
  await sleep(500);
}
return n;

// Human pause before submitting the login form: a uniform-random 20-30s wait.
// Also gives the background captcha-solver extension time to fill the reCAPTCHA
// token before we click, cutting down the 401020 'confirm you are not a robot'
// retries.
function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
var ms=20000+Math.floor(Math.random()*10001);   // 20000..30000
await sleep(ms);
return ms;
